/* ================================================================
 * Transight Design System — 타이포그래피
 *
 * 공개 API: typo-{weight}{size} 단일 클래스만 사용한다.
 *   <span class="typo-sb14">…</span>
 *
 * 굵기 약자 (100~900 전 범위):
 *   t=100(Thin) / el=200(ExtraLight) / l=300(Light)
 *   r=400(Regular) / m=500(Medium) / sb=600(Semibold)
 *   b=700(Bold) / eb=800(ExtraBold) / bk=900(Black)
 *
 * 크기 그리드:
 *   8 9 10 11 12 13 14 15 16    (1px 간격)
 *   18                           (레거시 유지)
 *   24 32 40 48 56               (8px 간격)
 *
 * 시맨틱 프리셋 (text-*): 크기+굵기+색까지 완결. 의미 명확하면 우선.
 *
 * SUIT / Pretendard 등 폰트 페이스는 fonts.css에서 @import (entry CSS 최상단).
 * ================================================================ */

@theme {
  --font-sans:
    'SUIT Variable', SUIT, -apple-system, BlinkMacSystemFont, system-ui, Roboto, 'Helvetica Neue',
    'Segoe UI', 'Apple SD Gothic Neo', 'Noto Sans KR', 'Malgun Gothic', 'Apple Color Emoji',
    'Segoe UI Emoji', 'Segoe UI Symbol', sans-serif;

  /* SUIT 자매 family — 디스플레이/약관/광고 등 톤 차별이 필요할 때 사용 */
  --font-pretendard:
    'Pretendard Variable', Pretendard, -apple-system, BlinkMacSystemFont, system-ui, Roboto,
    'Helvetica Neue', 'Segoe UI', 'Apple SD Gothic Neo', 'Noto Sans KR', 'Malgun Gothic',
    'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol', sans-serif;

  --font-mono:
    ui-monospace, SFMono-Regular, 'SF Mono', Menlo, Consolas, 'Liberation Mono', monospace;
}

/* ──────────────────────────────────────────────────────────────────
 * 내부 크기 atom (private) — public 합성용. 직접 사용 금지.
 * font-size + line-height + letter-spacing만 설정.
 * ────────────────────────────────────────────────────────────────── */

